import React, { useState } from 'react'

export const Login = () => {
    const [error,setError] = useState({ message: "Invalid Username", status: false })
  return (  
    <div className='login flex background text-[40px] w-[80%] h-[450px] bg-opacity-75 bg-white rounded-md'>
        <div className='logo w-[45%] h-full opacity-100'>
            <img className='w-full h-full rounded-md' src="./requiredfiles/image.png" alt="" />
        </div>
        <div align="center" className='content w-[55%] h-full opacity-100'>
            <div className='pt-[20px] heading text-[30px] font-[Barlow]'>
                Login
            </div>
            {error.status ? (
                <div class='error mt-[20px] text-[20px] font-[Barlow] w-[80%] text-white bg-[#FF8066] py-[10px] rounded-md transition-opacity duration-500 ease-in-out opacity-0 hover:opacity-100'>
                Invalid Username
              </div>
              
              
            ):(
                <div className='error opacity-0  mt-[20px] text-[20px] font-[Barlow] w-[80%] text-white py-[10px] rounded-md'>
                    Invalid Username
                </div>
            )}
            
            <div>
                <button onClick={()=>{
                    setError({...error,status:true})
                }}>Signin</button>
            </div>
            <div>
                <button onClick={()=>{
                    setError({...error,status:false})
                }}>clear</button>
            </div>
        </div>
    </div>
  )
}
